---
import '../styles/global.css';
import cjkFontsHref from '../styles/cjk-fonts.css?url';
import Header from '../components/Header.astro';
import Footer from '../components/Footer.astro';
import SEO from '../components/SEO.astro';
import { VisualEditing } from '@sanity/astro/visual-editing';
import { getAlternateUrl, type Lang } from '../lib/navigation';

interface Props {
  title: string;
  description?: string;
  lang?: string;
  jsonLd?: Record<string, unknown>;
  ogImage?: string;
  ogType?: string;
}

const {
  title,
  description = 'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY.',
  lang = 'en',
  jsonLd,
  ogImage,
  ogType,
} = Astro.props;

const gaMeasurementId = import.meta.env.PUBLIC_GA_MEASUREMENT_ID;
const googleSiteVerification = import.meta.env.PUBLIC_GOOGLE_SITE_VERIFICATION;

const alternateUrl = getAlternateUrl(Astro.url.pathname, lang as Lang);
const absoluteAlternateUrl = new URL(alternateUrl, Astro.site ?? 'https://ficcc.org').href;

const isVisualEditingEnabled =
  import.meta.env.PUBLIC_SANITY_VISUAL_EDITING_ENABLED === 'true';
---

<!doctype html>
<html lang={lang}>
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <SEO title={title} description={description} lang={lang} alternateUrl={absoluteAlternateUrl} jsonLd={jsonLd} ogImage={ogImage} ogType={ogType} />
    {googleSiteVerification && <meta name="google-site-verification" content={googleSiteVerification} />}
    <link rel="preconnect" href="https://cdn.sanity.io" crossorigin />
    <link rel="stylesheet" href={cjkFontsHref} media="print" onload="this.media='all'" />
    <noscript><link rel="stylesheet" href={cjkFontsHref} /></noscript>
  </head>
  <body>
    <a href="#main-content" class="skip-to-content">Skip to main content</a>
    <Header lang={lang} langToggleHref={alternateUrl} />
    <slot />
    <Footer lang={lang} />
    {isVisualEditingEnabled && <VisualEditing enabled={true} />}
    {gaMeasurementId && (
      <>
        <script async src={`https://www.googletagmanager.com/gtag/js?id=${gaMeasurementId}`}></script>
        <script define:vars={{ gaMeasurementId }}>
          window.dataLayer = window.dataLayer || [];
          function gtag() { dataLayer.push(arguments); }
          gtag('js', new Date());
          gtag('config', gaMeasurementId);

          // Custom event helper for sermon_play, language_switch, form_submit
          window.sendAnalyticsEvent = function(eventName, params) {
            if (typeof gtag === 'function') {
              gtag('event', eventName, params || {});
            }
          };
        </script>
      </>
    )}
    <script>
      document.addEventListener('click', (e) => {
        const toggle = (e.target as HTMLElement).closest('.lang-toggle') as HTMLAnchorElement | null;
        if (toggle) {
          const targetLang = toggle.href.includes('/zh') ? 'zh' : 'en';
          document.cookie = 'lang-pref=' + targetLang + ';path=/;max-age=31536000;SameSite=Lax';
        }
      });
    </script>
  </body>
</html>

<style is:global>
  .skip-to-content {
    position: absolute;
    left: -9999px;
    top: auto;
    width: 1px;
    height: 1px;
    overflow: hidden;
    z-index: 9999;
    padding: var(--space-3) var(--space-6);
    background: var(--color-ink);
    color: var(--color-bg);
    font-family: var(--font-body);
    font-size: var(--text-base);
    text-decoration: none;
    border-radius: var(--radius-sm, 0.25rem);
  }

  .skip-to-content:focus-visible {
    position: fixed;
    left: var(--space-4);
    top: var(--space-4);
    width: auto;
    height: auto;
    overflow: visible;
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }
</style>

---
import BaseLayout from '../layouts/BaseLayout.astro';
import Hero from '../components/Hero.astro';
import ServiceTimes from '../components/ServiceTimes.astro';
import ImageMosaic from '../components/ImageMosaic.astro';
import Pillars from '../components/Pillars.astro';
import Card from '../components/Card.astro';
import NextSteps from '../components/NextSteps.astro';
import { getHomePage, getSermons, getEvents, urlForImage } from '../lib/sanity';

const title = 'First Ithaca Chinese Christian Church | 伊的家華人基督教會';
const description =
  'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY. Sunday gathering at 9:45am, 429 Mitchell Street.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let homePage: Awaited<ReturnType<typeof getHomePage>> = null;
let sermons: Awaited<ReturnType<typeof getSermons>> = [];
let events: Awaited<ReturnType<typeof getEvents>> = [];

try {
  [homePage, sermons, events] = await Promise.all([
    getHomePage('en'),
    getSermons('en'),
    getEvents('en'),
  ]);
} catch {
  // Sanity unreachable (placeholder project, no network, etc.) — continue with fallbacks
}

// ---------- Fallback defaults ----------
const fallbackServiceTimes = [
  { label: 'Sunday Gathering', time: '9:45 AM' },
  { label: 'Sunday School', time: '11:15 AM' },
];

const fallbackPillars = [
  {
    title: 'Rooted in Scripture',
    description:
      "We hold to the Bible as God's inspired Word and the foundation for all of life and faith.",
  },
  {
    title: 'Christ-Centered Community',
    description:
      'We gather as a Christ-centered community, welcoming students, families, and neighbors of all backgrounds.',
  },
  {
    title: 'Bridging Cultures',
    description:
      'We celebrate our Chinese heritage while building a church home that bridges cultures and generations.',
  },
];

const fallbackNextSteps = [
  {
    title: 'Plan Your Visit',
    body: 'Join us Sunday at 9:45 AM. Learn what to expect and how to find us.',
    href: '/visit',
  },
  {
    title: 'Get Connected',
    body: 'Discover small groups, ministries, and ways to grow alongside others.',
    href: '/ministries',
  },
  {
    title: 'Watch Sermons',
    body: 'Catch up on recent messages or explore a teaching series.',
    href: '/sermons',
  },
];

// ---------- Resolved data (CMS ▸ fallback) ----------
const heroImage = homePage?.heroImage
  ? urlForImage(homePage.heroImage, { width: 1600 })
  : '/images/hero-placeholder.svg';
const heroTitle = homePage?.heroTitle || 'Welcome Home';
const heroSubtitle =
  homePage?.heroSubtitle ||
  'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY.';
const heroCtaText = homePage?.heroCtaText || 'Plan Your Visit';
const heroCtaHref = homePage?.heroCtaHref || '/visit';

const serviceTimes =
  homePage?.serviceTimes && homePage.serviceTimes.length > 0
    ? homePage.serviceTimes
    : fallbackServiceTimes;

const mosaicImages =
  homePage?.mosaicImages && homePage.mosaicImages.length > 0
    ? homePage.mosaicImages.map((img) => ({
        src: urlForImage(img, { width: 800 }),
        alt: img.alt || '',
      }))
    : Array.from({ length: 6 }, (_, i) => ({
        src: `/images/placeholder-${i + 1}.svg`,
        alt: `Church life ${i + 1}`,
      }));

const pillars =
  homePage?.pillars && homePage.pillars.length > 0
    ? homePage.pillars.map((p) => ({
        title: p.title,
        description: p.description || '',
      }))
    : fallbackPillars;

const nextSteps =
  homePage?.nextSteps && homePage.nextSteps.length > 0
    ? homePage.nextSteps.map((s) => ({
        title: s.title,
        body: s.body || '',
        href: s.href || '#',
        image: s.image ? urlForImage(s.image, { width: 600 }) : undefined,
      }))
    : fallbackNextSteps;

// ---------- Featured content ----------
const latestSermon = sermons[0] ?? null;
const nextEvent = events[0] ?? null;
---

<BaseLayout title={title} description={description}>
  <main id="main-content">
    <Hero
      title={heroTitle}
      subtitle={heroSubtitle}
      ctaText={heroCtaText}
      ctaHref={heroCtaHref}
      backgroundImage={heroImage}
    />

    <ServiceTimes times={serviceTimes} />

    <section class="mosaic-section" aria-label="Church Life">
      <div class="mosaic-section__inner">
        <ImageMosaic images={mosaicImages} />
      </div>
    </section>

    <Pillars pillars={pillars} />

    {(latestSermon || nextEvent) && (
      <section class="featured" aria-label="Featured">
        <div class="featured__inner">
          <h2 class="featured__heading">Stay Connected</h2>
          <div class="featured__grid">
            {latestSermon && (
              <Card
                title={latestSermon.title}
                body={latestSermon.speaker ? `Speaker: ${latestSermon.speaker}` : 'Latest sermon'}
                href="/sermons"
              />
            )}
            {nextEvent && (
              <Card
                title={nextEvent.title}
                body={nextEvent.date ? `Date: ${nextEvent.date}` : 'Upcoming event'}
                href="/events"
              />
            )}
          </div>
        </div>
      </section>
    )}

    <NextSteps steps={nextSteps} />
  </main>
</BaseLayout>

<style>
  .mosaic-section {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .mosaic-section__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .featured {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-stone);
  }

  .featured__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .featured__heading {
    font-family: var(--font-heading);
    font-size: var(--text-3xl);
    color: var(--color-ink);
    text-align: center;
    margin-block-end: var(--space-12);
  }

  .featured__grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: var(--space-8);
  }

  @media (max-width: 768px) {
    .featured__grid {
      grid-template-columns: 1fr;
      gap: var(--space-6);
    }

    .featured__heading {
      font-size: var(--text-2xl);
    }
  }
</style>

---
import BaseLayout from '../../layouts/BaseLayout.astro';
import Hero from '../../components/Hero.astro';
import YouTubeEmbed from '../../components/YouTubeEmbed.astro';
import { getSermons, type Sermon } from '../../lib/sanity';

export async function getStaticPaths() {
  let sermons: Sermon[] = [];

  try {
    sermons = await getSermons('en');
  } catch {
    // Sanity unreachable — return empty paths so build succeeds
  }

  return sermons
    .filter((s) => s.slug?.current)
    .map((sermon) => ({
      params: { slug: sermon.slug!.current },
      props: { sermon },
    }));
}

interface Props {
  sermon: Sermon;
}

const { sermon } = Astro.props;

const formattedDate = sermon.date
  ? new Date(sermon.date).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
    })
  : undefined;

const title = `${sermon.title} | Sermons | FICCC`;
---

<BaseLayout title={title}>
  <main id="main-content">
    <Hero
      title={sermon.title}
      subtitle={sermon.series ?? undefined}
      backgroundImage="/images/hero-placeholder.svg"
    />

    <article class="sermon-detail">
      <div class="sermon-detail__inner">
        <a class="sermon-detail__back" href="/sermons">← Back to Sermons</a>

        <div class="sermon-detail__meta">
          {sermon.speaker && (
            <div class="sermon-detail__meta-item">
              <span class="sermon-detail__label">Speaker</span>
              <span class="sermon-detail__value">{sermon.speaker}</span>
            </div>
          )}
          {formattedDate && (
            <div class="sermon-detail__meta-item">
              <span class="sermon-detail__label">Date</span>
              <span class="sermon-detail__value">{formattedDate}</span>
            </div>
          )}
          {sermon.scripture && (
            <div class="sermon-detail__meta-item">
              <span class="sermon-detail__label">Scripture</span>
              <span class="sermon-detail__value">{sermon.scripture}</span>
            </div>
          )}
          {sermon.series && (
            <div class="sermon-detail__meta-item">
              <span class="sermon-detail__label">Series</span>
              <span class="sermon-detail__value">{sermon.series}</span>
            </div>
          )}
        </div>

        {sermon.videoId && (
          <div class="sermon-detail__video">
            <YouTubeEmbed videoId={sermon.videoId} />
          </div>
        )}
      </div>
    </article>
  </main>
</BaseLayout>

<style>
  .sermon-detail {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .sermon-detail__inner {
    max-width: 48rem;
    margin-inline: auto;
  }

  /* ---------- Back link ---------- */
  .sermon-detail__back {
    display: inline-block;
    font-family: var(--font-body);
    font-size: var(--text-sm);
    font-weight: 500;
    color: var(--color-terracotta);
    text-decoration: none;
    margin-block-end: var(--space-8);
    transition: color var(--transition);
  }

  .sermon-detail__back:hover {
    color: #b3654b;
  }

  .sermon-detail__back:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  /* ---------- Metadata ---------- */
  .sermon-detail__meta {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: var(--space-6);
    margin-block-end: var(--space-10);
    padding: var(--space-8);
    background-color: var(--color-stone);
    border-radius: var(--radius-md);
  }

  .sermon-detail__meta-item {
    display: flex;
    flex-direction: column;
    gap: var(--space-1);
  }

  .sermon-detail__label {
    font-family: var(--font-body);
    font-size: var(--text-xs);
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: var(--color-body);
  }

  .sermon-detail__value {
    font-family: var(--font-body);
    font-size: var(--text-base);
    color: var(--color-ink);
  }

  /* ---------- Video ---------- */
  .sermon-detail__video {
    max-width: 100%;
  }

  /* ---------- Responsive ---------- */
  @media (max-width: 640px) {
    .sermon-detail {
      padding: var(--space-10) var(--space-4);
    }

    .sermon-detail__meta {
      grid-template-columns: 1fr;
      gap: var(--space-4);
      padding: var(--space-6);
    }
  }
</style>

---
import BaseLayout from '../layouts/BaseLayout.astro';
import Hero from '../components/Hero.astro';
import EventCard from '../components/EventCard.astro';
import { getEvents, urlForImage } from '../lib/sanity';
import type { Event } from '../lib/sanity';

const title = 'Events | First Ithaca Chinese Christian Church';
const description =
  'Upcoming events, gatherings, and activities at First Ithaca Chinese Christian Church.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let events: Event[] = [];

try {
  events = await getEvents('en');
} catch {
  // Sanity unreachable — continue with fallbacks
}

// ---------- Fallback events when CMS is empty ----------
const fallbackEvents: Event[] = [
  {
    _id: 'fallback-1',
    _type: 'event',
    title: 'Sunday Worship Service',
    date: new Date().toISOString(),
    time: 'Sundays 9:45 AM',
    location: '429 Mitchell Street, Ithaca, NY 14850',
    recurring: true,
    language: 'en',
  },
  {
    _id: 'fallback-2',
    _type: 'event',
    title: 'Sunday School',
    date: new Date().toISOString(),
    time: 'Sundays 11:15 AM',
    location: '429 Mitchell Street, Ithaca, NY 14850',
    recurring: true,
    language: 'en',
  },
  {
    _id: 'fallback-3',
    _type: 'event',
    title: 'Friday Fellowship',
    date: new Date().toISOString(),
    time: 'Fridays 7:00 PM',
    location: '429 Mitchell Street, Ithaca, NY 14850',
    recurring: true,
    language: 'en',
  },
];

const displayEvents = events.length > 0 ? events : fallbackEvents;

// ---------- Split into upcoming and past ----------
const now = new Date();
now.setHours(0, 0, 0, 0);

const upcomingEvents = displayEvents.filter((e) => {
  if (!e.date) return true; // No date — show in upcoming
  if (e.recurring) return true; // Recurring — always show in upcoming
  return new Date(e.date) >= now;
});

const pastEvents = displayEvents.filter((e) => {
  if (!e.date) return false;
  if (e.recurring) return false;
  return new Date(e.date) < now;
});
---

<BaseLayout title={title} description={description}>
  <main id="main-content">
    <Hero
      title="Events"
      subtitle="Join us for worship, fellowship, and community"
      backgroundImage="/images/hero-placeholder.svg"
    />

    <!-- Upcoming Events -->
    <section class="events-section" aria-label="Upcoming Events">
      <div class="events-section__inner">
        <h2 class="section-heading">Upcoming Events</h2>
        {upcomingEvents.length > 0 ? (
          <div class="events-grid">
            {upcomingEvents.map((event) => (
              <EventCard
                title={event.title}
                date={event.date || new Date().toISOString()}
                time={event.time}
                location={event.location}
                image={event.image ? urlForImage(event.image, { width: 600 }) : undefined}
                recurring={event.recurring}
              />
            ))}
          </div>
        ) : (
          <p class="events-empty">
            No upcoming events at the moment. Check back soon or follow us on social media for updates!
          </p>
        )}
      </div>
    </section>

    <!-- Past Events -->
    {pastEvents.length > 0 && (
      <section class="events-section events-section--past" aria-label="Past Events">
        <div class="events-section__inner">
          <h2 class="section-heading">Past Events</h2>
          <div class="events-grid">
            {pastEvents.map((event) => (
              <EventCard
                title={event.title}
                date={event.date || new Date().toISOString()}
                time={event.time}
                location={event.location}
                image={event.image ? urlForImage(event.image, { width: 600 }) : undefined}
                recurring={event.recurring}
              />
            ))}
          </div>
        </div>
      </section>
    )}
  </main>
</BaseLayout>

<style>
  .section-heading {
    font-family: var(--font-heading);
    font-size: var(--text-3xl);
    color: var(--color-ink);
    text-align: center;
    margin-block-end: var(--space-10);
  }

  .events-section {
    padding: var(--space-16) var(--space-6);
    background-color: var(--color-bg);
  }

  .events-section--past {
    background-color: var(--color-stone);
  }

  .events-section__inner {
    max-width: var(--max-width);
    margin-inline: auto;
  }

  .events-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(18rem, 1fr));
    gap: var(--space-8);
  }

  .events-empty {
    font-family: var(--font-body);
    font-size: var(--text-lg);
    line-height: var(--leading-relaxed);
    color: var(--color-body);
    text-align: center;
    max-width: 32rem;
    margin-inline: auto;
    padding: var(--space-8) 0;
  }

  @media (max-width: 768px) {
    .section-heading {
      font-size: var(--text-2xl);
    }

    .events-grid {
      grid-template-columns: 1fr;
    }
  }
</style>

---
import BaseLayout from '../../layouts/BaseLayout.astro';
import { getAboutPage, portableTextToHtml, urlForImage } from '../../lib/sanity';

const title = 'Who We Are | FICCC';
const description =
  'Learn about First Ithaca Chinese Christian Church — our history, mission, and community.';

// ---------- CMS data (graceful fallback when Sanity is unreachable) ----------
let aboutPage: Awaited<ReturnType<typeof getAboutPage>> = null;

try {
  aboutPage = await getAboutPage('en');
} catch {
  // Sanity unreachable — continue with fallbacks
}

// ---------- Fallback defaults ----------
const fallbackHeading = 'Who We Are';
const fallbackBody = `
<p>First Ithaca Chinese Christian Church (FICCC) was founded in 1968 by a small group of Chinese graduate students and scholars at Cornell University who longed for a Christ-centered community where they could worship in their heart language while welcoming the broader Ithaca community.</p>
<p>Over the decades the church has grown into a multigenerational, multicultural congregation that bridges Chinese heritage and American life. We gather every Sunday at 429 Mitchell Street for worship, teaching, and fellowship — in English and Mandarin — serving students, families, and neighbors throughout the Finger Lakes region.</p>
<p>Our mission is to glorify God by making disciples of Jesus Christ who love God wholeheartedly, love one another sacrificially, and reach out to the world with the Gospel. We believe the local church is God's primary instrument for advancing His kingdom, and we are committed to equipping every member for a life of faithful service.</p>
<p>Whether you are a longtime resident of Ithaca, a visiting scholar, or a student far from home, there is a place for you at FICCC. We invite you to come as you are and experience the warmth of Christ's love in community.</p>
`.trim();

const fallbackVisionHeading = 'Our Vision';
const fallbackVisionHtml = `
<p><strong>Develop Humble Servants Who Love the Lord, Love the Lost, Love the Local Church — For the Rest of Their Lives.</strong></p>
<p>Most of the students and scholars who walk through our doors will only be in Ithaca for a few years. But we believe that what happens during those years — the habits of worship, the depth of community, the encounters with Scripture — can shape the trajectory of an entire life.</p>
<p>Our vision is to nurture Christ-followers who don't just "do church" while they're here, but who carry the marks of discipleship wherever they go: into careers, families, churches, and communities around the world.</p>
`.trim();

const fallbackStats = [
  { value: '~150', label: 'Congregation Members' },
  { value: '~20', label: 'Baptisms Per Year' },
  { value: '18', label: 'Full-Time Ministers Sent' },
  { value: '40+', label: 'Years in Ithaca' },
];

// ---------- Resolved data (CMS ▸ fallback) ----------
const heading = aboutPage?.whoWeAreHeading || fallbackHeading;
const bodyHtml = aboutPage?.whoWeAreBody?.length
  ? portableTextToHtml(aboutPage.whoWeAreBody)
  : fallbackBody;
const imageUrl = aboutPage?.whoWeAreImage
  ? urlForImage(aboutPage.whoWeAreImage, { width: 800 })
  : '';

const visionHeading = aboutPage?.visionHeading || fallbackVisionHeading;
const visionHtml = aboutPage?.visionBody?.length
  ? portableTextToHtml(aboutPage.visionBody)
  : fallbackVisionHtml;

const stats =
  aboutPage?.churchStats && aboutPage.churchStats.length > 0
    ? aboutPage.churchStats
    : fallbackStats;
---

<BaseLayout title={title} description={description}>
  <main id="main-content" class="about">
    <section class="about__hero" aria-label="Who We Are">
      <div class="about__inner">
        <h1 class="about__heading">{heading}</h1>
        <div class="about__content">
          <div class="about__body" set:html={bodyHtml} />
          {imageUrl && (
            <div class="about__image-wrap">
              <img
                class="about__image"
                src={imageUrl}
                alt={heading}
                loading="lazy"
                width="800"
                height="533"
              />
            </div>
          )}
        </div>
      </div>
    </section>

    <!-- Vision Statement -->
    <section class="vision" aria-label="Our Vision">
      <div class="vision__inner">
        <h2 class="vision__heading">{visionHeading}</h2>
        <div class="vision__body" set:html={visionHtml} />
      </div>
    </section>

    <!-- Church Stats -->
    <section class="stats" aria-label="Church by the Numbers">
      <div class="stats__inner">
        <h2 class="stats__heading">By the Numbers</h2>
        <div class="stats__grid">
          {stats.map((stat) => (
            <div class="stats__item">
              <span class="stats__value">{stat.value}</span>
              <span class="stats__label">{stat.label}</span>
            </div>
          ))}
        </div>
      </div>
    </section>
  </main>
</BaseLayout>

<style>
  .about {
